from typing import List

class Solution:
    def maximumCount(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        def sieve(n):
            primes = [True] * (n + 1)
            primes[0] = primes[1] = False
            for i in range(2, int(n ** 0.5) + 1):
                if primes[i]:
                    for j in range(i * i, n + 1, i):
                        primes[j] = False
            return [i for i in range(n + 1) if primes[i]]

        primes = sieve(10 ** 5)
        prime_set = set(primes)
        n = len(nums)
        prefix_primes = [0] * n
        for i in range(n):
            if nums[i] in prime_set:
                prefix_primes[i] = 1 if i == 0 else prefix_primes[i - 1] + 1
            else:
                prefix_primes[i] = 0 if i == 0 else prefix_primes[i - 1]

        results = []
        for idx, val in queries:
            old_val = nums[idx]
            nums[idx] = val

            if old_val in prime_set and val not in prime_set:
                for i in range(idx, n):
                    prefix_primes[i] -= 1
            elif old_val not in prime_set and val in prime_set:
                for i in range(idx, n):
                    prefix_primes[i] += 1

            max_count = 0
            count_left = 0
            for i in range(n - 1):
                count_left += 1 if nums[i] in prime_set else 0
                count_right = prefix_primes[n - 1] - count_left
                max_count = max(max_count, count_left + count_right)

            results.append(max_count)
        return results
